#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        long long ans = 0;
        for(int i=0;i+2<N;i++){
            if(a[i]!=a[i+1] && a[i]!=a[i+2] && a[i+1]!=a[i+2]){
                ans++;
                a[i+2] = a[i+1]; // simulate change
            }
        }
        printf("%lld\n", ans);
        free(a);
    }
    return 0;
}

